/*【◈油画信纸◈】作者：易碎蝶*/

/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/309/main/result.css");

body {
    font-family: "KingHwa_OldSong";
    font-weight: normal;
}
/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 90px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background: url("https://i.postimg.cc/0j0DZXX9/Image-4788891985080516.png") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 2px;
    bottom: -10px;

    /* 层级控制 */
    z-index: 3004;
    pointer-events: auto;

    /* 移除动画相关属性 */
    transform: none !important;
    animation: none !important;
}

/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/3JCC8NBd/Camera-XHS-17488482939611040g00831ckqis060e105p57s5ck6idn7g2nla8.jpg'); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 45px;
  height: 45px;
  background: transparent url('https://i.postimg.cc/6qwwpT05/Image-4765774398478369.png') center/cover no-repeat;
  border: none;
  border-radius: 0;
  box-shadow: none;
  cursor: ew-resize;
  position: relative;
  z-index: 1;
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 装饰层模块
 * ==============================================*/
/* 上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -195px; /* 调整上层装饰层与气泡顶部的距离(负值表示向上) */
  left: -39px; /* 调整上层装饰层的水平位置 */
  width: 425px; /* 调整上层装饰层的宽度 */
  height: 440px; /* 调整上层装饰层的高度 */
  background-image: url('https://i.postimg.cc/L40DBjzf/Image-4763263345720065.png'); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 40; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -461.2px; /* 调整下层装饰层与气泡底部的距离(负值表示向下) */
  right: -52.5px; /* 调整下层装饰层的水平位置 */
  width: 451px; /* 调整下层装饰层的宽度 */
  height: 470px; /* 调整下层装饰层的高度 */
  background-image: url('https://i.postimg.cc/Hxy5yh4S/Image-4786327953482209.png'); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 42; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————修复右边距过大——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 可独立调整的边距系统 */
    --top-padding: 3rem; /* 气泡顶部留白（可单独调整） */
    --bottom-padding: 3rem; /* 气泡底部留白（可单独调整） */
    --left-padding: 0.4rem; /* 气泡左边距（控制文本与左侧边界距离） */
    --right-padding: 0.67rem; /* 气泡右边距（控制文本与右侧边界距离） */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 19px; */
}



/*——————最新消息箭头图标替换——————*/
/* 隐藏原有字体图标 */
.fa-chevron-right:before,
.fa-chevron-left:before {
  content: "" !important;
}

/* 左箭头图片容器 */
.fa-chevron-left {
  display: inline-block;
  width: 70px; /* 图片宽度 */
  height: 30px; /* 图片高度 */
  background: url('https://i.postimg.cc/zfPLjbC2/Image-4796020272926787.png') center/contain no-repeat;
  /* ↑ 替换为您的左箭头图片链接 ↑ */
}

/* 右箭头图片容器 */
.fa-chevron-right {
  display: inline-block;
  width: 80px; /* 图片宽度 */
  height: 30px; /* 图片高度 */
  background: url('https://i.postimg.cc/zfPLjbC2/Image-4796020272926787.png') center/contain no-repeat;
  /* ↑ 替换为您的右箭头图片链接 ↑ */
}

.swipes-counter {
  color: var(--SmartThemeBodyColor);
  font-size: 10px;
  /* 位置调整 */
  margin: var(--counter-vertical, 0) var(--counter-horizonta, 0); /* 垂直 水平 */
  /* 或使用绝对定位 */
  /* position: relative;
  left: var(--counter-left, 0);
  top: var(--counter-top, 0); */

  padding: 0 50px;
  font-family: var(--mainFontFamily);
  font-weight: 40;
  align-self: center;
  min-width: 100px;
  display: flex;
  justify-content: center;
  margin-bottom: var(--swipeCounterMargin);
  height: var(--swipeCounterHeight);
}

.fa-arrow-right:before {
    display: none !important;
}

/*——————气泡设置——————*/

/* ==============================================
 * 1. 气泡容器模块
 * ==============================================*/
.mes {
  max-width: 350px;
  width: 500%;
  margin: 170px auto 170px;
  border-radius: 0px;
  /* 移除渐变背景和阴影 */
  background: url('https://i.postimg.cc/vZXj7JTH/Image-4760876068720230.png') repeat-y; /* 添加重复方向 */
  background-size: 100% auto; /* 保持宽度适配 */
  background-attachment: local; /* 确保滚动时背景同步 */
  transition: transform 0.2s ease; /* 移除阴影过渡 */
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; /* 强制移除所有阴影 */
}



/* ==============================================
 * 2. 头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -130px;           /* 控制头像在气泡上方的位置 */
  left: 41%;            /* 水平居中 */
  transform: translateX(-50%);
  z-index: 10;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 基础尺寸 - 可自定义修改 */
  width: 120px;           /* 头像宽度 */
  height: 120px;          /* 头像高度 */

  /* 形状控制 - 默认圆形 */
  border-radius: 50%;    /* 圆形（50%），可修改为不同值创建椭圆或圆角矩形 */

  /* 外观样式 */
  overflow: hidden;
  border: 3px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  transition: all 0.3s ease;
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}


/* ==============================================
 * 4. 楼层显示
 * ============================================== */
.mes .mesIDDisplay {
    position: fixed;  /* 使用固定定位 */
    top: 200;           /* 固定在顶部 */
    left: 10%;        /* 水平居中 */
    transform: translateX(-50%); /* 精确居中 */
    z-index: 99;    /* 确保在最顶层 */
    margin-top: 15px; /* 适当留白 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.4); /* 半透明白底 */
    border-radius: 4px;
    box-shadow: 90 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    color: #333; /* 增加颜色确保可读性 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    text-align: center;
}
/* ==============================================
 * 5. 基础信息位置调整
 * ============================================== */
.mes_block {
  position: relative; /* 保留定位基准 */
}

/* 关键：用伪元素作为占位符，占据 .ch_name 的空间 */
.mes_block::before {
  content: ""; /* 必须属性 */
  display: block; /* 块级元素，占据空间 */
  height: 15px; /* 手动设置占位高度，需与 .ch_name 的实际高度一致 */
  /* 若 .ch_name 高度由内容决定，可改为 min-height 或通过 JS 动态获取 */
}

.mes_block .ch_name {
  max-width: calc(100% - 105px); /* 原 left:95px + right:10px = 145px 留白 */
  min-height: 50px;
  position: absolute; /* 保持绝对定位，自由控制位置 */
  top: 0.5; /* 顶部紧贴 */
  left: 78px; /* 左侧偏移 90px */
  right: 55px; /* 右侧留白 10px */
  /* 移除 bottom，避免强制撑开高度 */
}
}

