/*——————复选——————*/
<!DOCTYPE html>
<html>
<head>
<style>
/* 清新绿风格 - 低饱和莫兰迪色彩 */
body {
  background: #f8fcf8; /* 柔和的浅绿色背景 */
}

input[type='checkbox'] {
  appearance: none;
  width: 20px;
  height: 20px;
  border: 2px solid #a6c1ac; /* 柔和的灰绿色边框 */
  border-radius: 5px;
  cursor: pointer;
  position: relative;
  background: #f0f7f2; /* 浅薄荷色背景 */
  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.27, 1.55);
  box-shadow: 
    inset 0 0 2px rgba(166, 193, 172, 0.3), /* 柔和的绿色内阴影 */
    0 2px 8px rgba(166, 193, 172, 0.15);
}

input[type='checkbox']:hover {
  transform: scale(1.1);
  box-shadow: 
    inset 0 0 10px rgba(166, 193, 172, 0.4),
    0 0 15px rgba(166, 193, 172, 0.2);
  border-color: #8aac94; /* 稍深的绿色悬停边框 */
}

input[type='checkbox']:checked {
  background: #d7e9dc; /* 柔和的薄荷绿背景 */
  border-color: #7a9a85; /* 深绿色边框 */
  animation: jelly 0.6s ease;
  box-shadow: 
    inset 0 0 10px rgba(122, 154, 133, 0.3),
    0 2px 12px rgba(166, 193, 172, 0.15);
}

input[type='checkbox']:checked::after {
  content: '◾︎'; /* 保留复古十字标记 */
  position: absolute;
  top: 50%;
  left: 46%;
  transform: translate(-50%, -55%) rotate(0deg);
  color: #7a9a85; /* 深绿色标记 */
  font-size: 23px;
  font-weight: bold;
  text-shadow: 0 1px 4px rgba(122, 154, 133, 0.2);
}

#waifuMode:checked {
  background: #c8dfd0; /* 稍深的薄荷绿背景 */
  border-color: #8aac94; /* 绿色边框 */
  box-shadow: 
    inset 0 0 12px rgba(138, 172, 148, 0.3),
    0 0 22px rgba(166, 193, 172, 0.15);
}

#waifuMode:checked::after {
  content: '✦'; /* 保留复古星形标记 */
  color: #7a9a85;
  animation: antiqueGlow 1.5s ease-in-out infinite;
}

@keyframes jelly {
  0% { transform: scale(1); }
  30% { transform: scale(1.25); }
  60% { transform: scale(0.9); }
  100% { transform: scale(1); }
}

@keyframes antiqueGlow {
  0% { text-shadow: 0 0 5px rgba(122, 154, 133, 0.1); }
  50% { text-shadow: 0 0 12px rgba(138, 172, 148, 0.3); }
  100% { text-shadow: 0 0 5px rgba(122, 154, 133, 0.1); }
}



/* 添加一些装饰元素增强清新感 */
.container {
  display: flex;
