  transform: scale(1.02);
  border-color: rgba(200, 215, 200, 0.9);
  background-color: rgba(252, 254, 252, 0.98);

  box-shadow: 
    inset 1px 1px 4px rgba(255, 255, 255, 0.9),
    4px 4px 12px rgba(170, 185, 170, 0.35);
}

