  outline: none;
  border-color: rgba(190, 210, 190, 0.9);
  background-color: rgba(255, 255, 255, 1);

  box-shadow: 
    inset 1px 1px 5px rgba(255, 255, 255, 0.95),
    0 0 0 3px rgba(200, 215, 200, 0.3),
    5px 5px 16px rgba(160, 180, 160, 0.4);

  animation: jellyFocus 0.9s ease;
}

.drawer-content select option {
  background: rgba(252, 254, 252, 0.98);
  color: #7a9d8a;
  padding: 2px 20px;
  margin: 4px 0;
  border-radius: 12px;
  transition: all 0.3s ease;
}

